class KthLargest {
public:
    KthLargest(int k, vector<int>& nums) {
        this->k = k;
        for (int num : nums) {
            add(num);
        }
        priority_queue<int, vector<int>, greater<int>> pq;
        for (int i = 0; i < k; i++) {
            pq.push(nums[i]);
        }
        for (int i = k; i < nums.size(); i++) {
            if (nums[i] > pq.top()) {
                pq.pop();
                pq.push(nums[i]);
            }
        }
        pq_ = pq;
    }

    int add(int val) {
        if (pq_.size() < k) {
            pq_.push(val);
        } else if (val > pq_.top()) {
            pq_.pop();
            pq_.push(val);
        }
        return pq_.top();
    }
private:
    int k;
    priority_queue<int, vector<int>, greater<int>> pq_;
};
```

efficiency: HIGH
time complexity: O(n log n) for initialization and O(log k) for add operation
space complexity: O(k)
